class InputValidator {
    private static final Pattern EMPLOYEE_ID_PATTERN = Pattern.compile("^EMP-[0-9]{5,10}$");
    private static final Pattern NAME_PATTERN = Pattern.compile("^[a-zA-Z\\s\\-'.]{1,100}$");
    private static final Pattern DEPARTMENT_PATTERN = Pattern.compile("^[a-zA-Z\\s\\-]{1,50}$");
    private static final double MIN_SALARY = 0.0;
    private static final double MAX_SALARY = 10_000_000.0;

    private static final Set<String> VALID_RATINGS = Set.of(
        "EXCEPTIONAL", "EXCEEDS_EXPECTATIONS", "MEETS_EXPECTATIONS",
        "NEEDS_IMPROVEMENT", "UNSATISFACTORY", "NOT_REVIEWED"
    );

    private static final Set<String> VALID_TERMINATION_REASONS = Set.of(
        "VOLUNTARY_RESIGNATION", "LAYOFF", "PERFORMANCE",
        "MISCONDUCT", "RETIREMENT", "CONTRACT_END"
    );

    private static final Set<String> VALID_ROLES = Set.of(
        "HR_ADMIN", "HR_MANAGER", "PAYROLL_ADMIN"
    );

    public static boolean isValidEmployeeId(String employeeId) {
        return employeeId != null && EMPLOYEE_ID_PATTERN.matcher(employeeId).matches();
    }

    public static boolean isValidName(String name) {
        return name != null && NAME_PATTERN.matcher(name).matches();
    }

    public static boolean isValidDepartment(String department) {
        return department != null && DEPARTMENT_PATTERN.matcher(department).matches();
    }

    public static boolean isValidSalary(double salary) {
        return salary >= MIN_SALARY && salary <= MAX_SALARY && Double.isFinite(salary);
    }

    public static boolean isValidPerformanceRating(String rating) {
        return rating != null && VALID_RATINGS.contains(rating.toUpperCase());
    }

    public static boolean isValidTerminationReason(String reason) {
        return reason != null && VALID_TERMINATION_REASONS.contains(reason.toUpperCase());
    }

    public static boolean isValidRole(String role) {
        return role != null && VALID_ROLES.contains(role.toUpperCase());
    }

    public static String sanitize(String input) {
        if (input == null) return null;
        return input.trim()
            .replaceAll("[<>&\"']", "")
            .replaceAll("\\p{Cntrl}", "");
    }
}

