@WebService(
    name = "EmployeeManagementService",
    serviceName = "EmployeeManagementService",
    targetNamespace = "urn:internal:hr:employee-management"
)
class EmployeeManagementServiceImpl {
    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceImpl.class.getName());

    // In production, this would be a proper database with encrypted connections
    private static final Map<String, EmployeeRecord> employeeStore = new ConcurrentHashMap<>();

    @Resource
    private WebServiceContext wsContext;

    static {
        // Sample data for demonstration
        employeeStore.put("EMP-00001", new EmployeeRecord("EMP-00001", "John Smith", 75000.0, "Engineering"));
        employeeStore.put("EMP-00002", new EmployeeRecord("EMP-00002", "Jane Doe", 82000.0, "Marketing"));
        employeeStore.put("EMP-00003", new EmployeeRecord("EMP-00003", "Bob Johnson", 68000.0, "Finance"));
    }

    // --------------------------------------------------------
    // Authentication Endpoint
    // --------------------------------------------------------

    @WebMethod(operationName = "authenticate")
    public ServiceResponse authenticate(
            @WebParam(name = "username") String username,
            @WebParam(name = "password") String password) {

        if (username == null || password == null ||
            username.length() > 50 || password.length() > 128) {
            return new ServiceResponse(false, "Invalid credentials format", "AUTH_001");
        }

        String token = AuthService.authenticate(username, password);
        if (token == null) {
            AuditLogger.logSecurityEvent("AUTH_FAILURE", "Failed authentication attempt");
            return new ServiceResponse(false, "Authentication failed", "AUTH_002");
        }

        AuditLogger.logOperation("AUTHENTICATE", "N/A", username, true);
        // Token returned to client for subsequent requests
        return new ServiceResponse(true, token);
    }

    // --------------------------------------------------------
    // Salary Update Operation
    // --------------------------------------------------------

    @WebMethod(operationName = "updateSalary")
    public ServiceResponse updateSalary(
            @WebParam(name = "authToken") String authToken,
            @WebParam(name = "employeeId") String employeeId,
            @WebParam(name = "newSalary") double newSalary,
            @WebParam(name = "reason") String reason) {

        // Authorization check - only HR_ADMIN and PAYROLL_ADMIN can update salary
        if (!AuthService.isAuthorized(authToken, "HR_ADMIN", "PAYROLL_ADMIN")) {
            AuditLogger.logSecurityEvent("UNAUTHORIZED_ACCESS", "Salary update attempt without authorization");
            return new ServiceResponse(false, "Unauthorized access", "AUTHZ_001");
        }

        AuthService.AuthToken tokenInfo = AuthService.validateToken(authToken);

        // Input validation
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            return new ServiceResponse(false, "Invalid employee ID format", "VAL_001");
        }

        if (!InputValidator.isValidSalary(newSalary)) {
            return new ServiceResponse(false, "Invalid salary value", "VAL_002");
        }

        String sanitizedReason = InputValidator.sanitize(reason);
        if (sanitizedReason == null || sanitizedReason.isEmpty() || sanitizedReason.length() > 500) {
            return new ServiceResponse(false, "Valid reason is required (max 500 characters)", "VAL_003");
        }

        // Business logic
        EmployeeRecord employee = employeeStore.get(employeeId);
        if (employee == null) {
            return new ServiceResponse(false, "Employee not found", "BUS_001");
        }

        if (!employee.isActive()) {
            return new ServiceResponse(false, "Cannot update salary for terminated employee", "BUS_002");
        }

        // Salary change limit validation (max 50% increase per update)
        double currentSalary = employee.getSalary();
        if (newSalary > currentSalary * 1.5) {
            AuditLogger.logSecurityEvent("EXCESSIVE_SALARY_CHANGE",
                "Attempted salary increase exceeding 50% for employee");
            return new ServiceResponse(false,
                "Salary increase exceeds maximum allowed percentage. Requires additional approval.", "BUS_003");
        }

        employee.setSalary(newSalary);
        // Do NOT log the actual salary amount
        AuditLogger.logOperation("SALARY_UPDATE", employeeId, tokenInfo.username, true);

        return new ServiceResponse(true, "Salary updated successfully");
    }

    // --------------------------------------------------------
    // Performance Review Operation
    // --------------------------------------------------------

    @WebMethod(operationName = "submitPerformanceReview")
    public ServiceResponse submitPerformanceReview(
            @WebParam(name = "authToken") String authToken,
            @WebParam(name = "employeeId") String employeeId,
            @WebParam(name = "rating") String rating,
            @WebParam(name = "reviewNotes") String reviewNotes,
            @WebParam(name = "reviewPeriod") String reviewPeriod) {

        // Authorization check - only HR_ADMIN and HR_MANAGER can submit reviews
        if (!AuthService.isAuthorized(authToken, "HR_ADMIN", "HR_MANAGER")) {
            AuditLogger.logSecurityEvent("UNAUTHORIZED_ACCESS", "Performance review attempt without authorization");
            return new ServiceResponse(false, "Unauthorized access", "AUTHZ_001");
        }

        AuthService.AuthToken tokenInfo = AuthService.validateToken(authToken);

        // Input validation
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            return new ServiceResponse(false, "Invalid employee ID format", "VAL_001");
        }

        if (!InputValidator.isValidPerformanceRating(rating)) {
            return new ServiceResponse(false,
                "Invalid rating. Must be one of: EXCEPTIONAL, EXCEEDS_EXPECTATIONS, MEETS_EXPECTATIONS, NEEDS_IMPROVEMENT, UNSATISFACTORY",
                "VAL_004");
        }

        String sanitizedNotes = InputValidator.sanitize(reviewNotes);
        if (sanitizedNotes == null || sanitizedNotes.isEmpty() || sanitizedNotes.length() > 2000) {
            return new ServiceResponse(false, "Review notes required (max 2000 characters)", "VAL_005");
        }

        String sanitizedPeriod = InputValidator.sanitize(reviewPeriod);
        if (sanitizedPeriod == null || !sanitizedPeriod.matches("^(Q[1-4]|H[1-2]|ANNUAL)-\\d{4}$")) {
            return new ServiceResponse(false, "Invalid review period format. Use Q1-2024, H1-2024, or ANNUAL-2024", "VAL_006");
        }

        // Business logic
        EmployeeRecord employee = employeeStore.get(employeeId);
        if (employee == null) {
            return new ServiceResponse(false, "Employee not found", "BUS_001");
        }

        if (!employee.isActive()) {
            return new ServiceResponse(false, "Cannot review terminated employee", "BUS_004");
        }

        employee.setPerformanceRating(rating.toUpperCase());
        AuditLogger.logOperation("PERFORMANCE_REVIEW", employeeId, tokenInfo.username, true);

        return new ServiceResponse(true, "Performance review submitted successfully for period " + sanitizedPeriod);
    }

    // --------------------------------------------------------
    // Get Performance Review Operation
    // --------------------------------------------------------

    @WebMethod(operationName = "getPerformanceRating")
    public ServiceResponse getPerformanceRating(
            @WebParam(name = "authToken") String authToken,
            @WebParam(name = "employeeId") String employeeId) {

        // Authorization check
        if (!AuthService.isAuthorized(authToken, "HR_ADMIN", "HR_MANAGER")) {
            AuditLogger.logSecurityEvent("UNAUTHORIZED_ACCESS", "Performance rating access attempt without authorization");
            return new ServiceResponse(false, "Unauthorized access", "AUTHZ_001");
        }

        if (!InputValidator.isValidEmployeeId(employeeId)) {
            return new ServiceResponse(false, "Invalid employee ID format", "VAL_001");
        }

        EmployeeRecord employee = employeeStore.get(employeeId);
        if (employee == null) {
            return new ServiceResponse(false, "Employee not found", "BUS_001");
        }

        AuthService.AuthToken tokenInfo = AuthService.validateToken(authToken);
        AuditLogger.logOperation("GET_PERFORMANCE_RATING", employeeId, tokenInfo.username, true);

        return new ServiceResponse(true, employee.getPerformanceRating());
    }

    // --------------------------------------------------------
    // Employee Termination Operation
    // --------------------------------------------------------

    @WebMethod(operationName = "terminateEmployee")
    public ServiceResponse terminateEmployee(
            @WebParam(name = "authToken") String authToken,
            @WebParam(name = "employeeId") String employeeId,
            @WebParam(name = "terminationReason") String terminationReason,
            @WebParam(name = "effectiveDate") String effectiveDate) {

        // Authorization check - only HR_ADMIN can terminate
        if (!AuthService.isAuthorized(authToken, "HR_ADMIN")) {
            AuditLogger.logSecurityEvent("UNAUTHORIZED_ACCESS", "Termination attempt without HR_ADMIN authorization");
            return new ServiceResponse(false, "Unauthorized access. HR_ADMIN role required.", "AUTHZ_002");
        }

        AuthService.AuthToken tokenInfo = AuthService.validateToken(authToken);

        // Input validation
        if (!InputValidator.isValidEmployeeId(employeeId)) {
            return new ServiceResponse(false, "Invalid employee ID format", "VAL_001");
        }

        if (!InputValidator.isValidTerminationReason(terminationReason)) {
            return new ServiceResponse(false,
                "Invalid termination reason. Must be one of: VOLUNTARY_RESIGNATION, LAYOFF, PERFORMANCE, MISCONDUCT, RETIREMENT, CONTRACT_END",
                "VAL_007");
        }

        String sanitizedDate = InputValidator.sanitize(effectiveDate);
        if (sanitizedDate == null || !sanitizedDate.matches("^\\d{4}-\\d{2}-\\d{2}$")) {
            return new ServiceResponse(false, "Invalid date format. Use YYYY-MM-DD", "VAL_008");
        }

        // Validate date is not in the past (basic check)
        try {
            java.time.LocalDate date = java.time.LocalDate.parse(sanitizedDate);
            if (date.isBefore(java.time.LocalDate.now())) {
                return new ServiceResponse(false, "Effective date cannot be in the past", "VAL_009");
            }
        } catch (Exception e) {
            return new ServiceResponse(false, "Invalid date", "VAL_008");
        }

        // Business logic
        EmployeeRecord employee = employeeStore.get(employeeId);
        if (employee == null) {
            return new ServiceResponse(false, "Employee not found", "BUS_001");
        }

        if (!employee.isActive()) {
            return new ServiceResponse(false, "Employee is already terminated", "BUS_005");
        }

        employee.setActive(false);
        AuditLogger.logOperation("TERMINATION", employeeId, tokenInfo.username, true);

        return new ServiceResponse(true, "Employee termination processed. Effective date: " + sanitizedDate);
    }

    // --------------------------------------------------------
    // Logout Operation
    // --------------------------------------------------------

    @WebMethod(operationName = "logout")
    public ServiceResponse logout(@WebParam(name = "authToken") String authToken) {
        if (authToken != null) {
            AuthService.AuthToken tokenInfo = AuthService.validateToken(authToken);
            if (tokenInfo != null) {
                AuditLogger.logOperation("LOGOUT", "N/A", tokenInfo.username, true);
            }
            AuthService.invalidateToken(authToken);
        }
        return new ServiceResponse(true, "Logged out successfully");
    }
}

