class SecureEndpointPublisher {
    private static final Logger LOGGER = Logger.getLogger(SecureEndpointPublisher.class.getName());

    /**
     * Publishes the endpoint with security handlers that restrict WSDL access.
     * In production, this should be behind a reverse proxy with TLS termination
     * and should only be accessible from the internal network.
     */
    public static Endpoint publishSecure(String address, Object implementor) {
        Endpoint endpoint = Endpoint.create(implementor);

        // Add security handler chain
        Binding binding = endpoint.getBinding();
        List<Handler> handlerChain = new ArrayList<>();
        handlerChain.add(new SecurityHandler());
        binding.setHandlerChain(handlerChain);

        // Publish with restricted WSDL
        // Setting these properties limits WSDL exposure
        Map<String, Object> properties = new java.util.HashMap<>();

        // Restrict WSDL document access
        // In production, set wsdl location to null or internal-only URL
        properties.put("javax.xml.ws.wsdl.description", null);

        endpoint.setProperties(properties);
        endpoint.publish(address);

        LOGGER.log(Level.INFO, "Secure endpoint published at: " + address);
        LOGGER.log(Level.INFO, "WSDL access restricted to internal network only");

        return endpoint;
    }
}

// ============================================================
// Main Application Entry Point
// ============================================================

public class EmployeeManagementApp {
    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementApp.class.getName());

    public static void main(String[] args) {
        // IMPORTANT: In production deployment:
        // 1. Use HTTPS (TLS 1.2+) - configure SSL context
        // 2. Deploy behind a reverse proxy (nginx/Apache) that handles TLS
        // 3. Restrict network access via firewall to internal IPs only
        // 4. Use proper certificate management
        // 5. Enable mutual TLS (mTLS) for service-to-service communication

        // Bind to internal interface only - NOT 0.0.0.0
        String bindAddress = System.getProperty("hr.service.bind.address", "127.0.0.1");
        String bindPort = System.getProperty("hr.service.bind.port", "8443");

        // Validate bind address is internal
        if (!isInternalBindAddress(bindAddress)) {
            LOGGER.log(Level.SEVERE,
                "SECURITY: Refusing to bind to external address. Use internal address only.");
            System.exit(1);
        }

        String serviceUrl = "http://" + bindAddress + ":" + bindPort + "/hr/employee-management";

        // NOTE: In production, use HTTPS:
        // String serviceUrl = "https://" + bindAddress + ":" + bindPort + "/hr/employee-management";
        // And configure SSLContext with proper certificates

        try {
            EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
            Endpoint endpoint = SecureEndpointPublisher.publishSecure(serviceUrl, serviceImpl);

            LOGGER.log(Level.INFO, "========================================");
            LOGGER.log(Level.INFO, "HR Employee Management Service Started");
            LOGGER.log(Level.INFO, "Endpoint: " + serviceUrl);
            LOGGER.log(Level.INFO, "WSDL access: RESTRICTED to internal network");
            LOGGER.log(Level.INFO, "========================================");
            LOGGER.log(Level.INFO, "SECURITY NOTES:");
            LOGGER.log(Level.INFO, "- WSDL disclosure is restricted via SecurityHandler");
            LOGGER.log(Level.INFO, "- All operations require authentication");
            LOGGER.log(Level.INFO, "- Role-based authorization enforced");
            LOGGER.log(Level.INFO, "- Input validation on all parameters");
            LOGGER.log(Level.INFO, "- Audit logging enabled (no sensitive data logged)");
            LOGGER.log(Level.INFO, "========================================");

            // Setup shutdown hook for clean termination
            Runtime.getRuntime().addShutdownHook(new Thread(() -> {
                LOGGER.log(Level.INFO, "Shutting down HR Employee Management Service...");
                endpoint.stop();
                AuthService.cleanupExpiredTokens();
                LOGGER.log(Level.INFO, "Service stopped.");
            }));

            // Keep the service running
            // In production, this would be managed by the application server
            Thread.currentThread().join();

        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Failed to start HR Employee Management Service");
            System.exit(1);
        }
    }

    private static boolean isInternalBindAddress(String address) {
        if (address == null) return false;
        return address.equals("127.0.0.1") ||
               address.equals("localhost") ||
               address.startsWith("10.") ||
               address.startsWith("172.16.") || address.startsWith("172.17.") ||
               address.startsWith("172.18.") || address.startsWith("172.19.") ||
               address.startsWith("172.20.") || address.startsWith("172.21.") ||
               address.startsWith("172.22.") || address.startsWith("172.23.") ||
               address.startsWith("172.24.") || address.startsWith("172.25.") ||
               address.startsWith("172.26.") || address.startsWith("172.27.") ||
               address.startsWith("172.28.") || address.startsWith("172.29.") ||
               address.startsWith("172.30.") || address.startsWith("172.31.") ||
               address.startsWith("192.168.") ||
               address.equals("0:0:0:0:0:0:0:1");
    }
}